import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface RecentFeedback {
  comment: string;
  sentiment: string;
}

interface CustomerSatisfactionData {
  npsScore: number;
  trend: number[];
  recentFeedback: RecentFeedback[];
}

export default function Widget() {
  const customerSatisfactionData = response.data as CustomerSatisfactionData;
  const { npsScore, trend, recentFeedback } = customerSatisfactionData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ color: '#4CAF50' }}>
              NPS Score
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ color: '#4CAF50' }}>
              {npsScore}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 100 }}>
            <LineChart
              height={80}
              series={[
                {
                  data: trend,
                  color: '#FFC107',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: trend.map((_, i) => i), hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>

          <Stack spacing={1}>
            {recentFeedback.slice(0, 3).map((feedback, index) => (
              <Box key={index}>
                <Typography variant="body2" fontWeight={500}>
                  {feedback.comment}
                </Typography>
                <Chip
                  label={feedback.sentiment.charAt(0).toUpperCase() + feedback.sentiment.slice(1)}
                  sx={{ mt: 0.5, fontSize: '10px', color: '#FFFFFF', bgcolor: feedback.sentiment === 'positive' ? '#4CAF50' : feedback.sentiment === 'neutral' ? '#FFC107' : '#F44336' }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
